"use client";

import { ArrowLeft, CheckCircle, Package, User, XCircle } from "lucide-react";
import { useParams, useRouter } from "next/navigation";
import { useEffect, useState } from "react";

const BASE_URL = "http://localhost:5000";

const ItemDetailsPage = () => {
  const { id } = useParams();
  const router = useRouter();

  const [item, setItem] = useState(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [actionStatus, setActionStatus] = useState("");

  // ================= FETCH ITEM =================
  useEffect(() => {
    if (!id) return;

    const fetchItem = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/item/details/${id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to load item");
        const data = await res.json();
        setItem(data);
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchItem();
  }, [id]);

  // ================= ACTION HANDLER =================
  const handleAction = async (endpoint, successText) => {
    setActionLoading(true);
    setActionStatus(`${successText} in progress...`);
    try {
      const token = localStorage.getItem("accessToken");
      const res = await fetch(`${BASE_URL}/admin/${endpoint}/${id}`, {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) throw new Error("Action failed");

      setActionStatus(successText);
      // update item status locally
      setItem((prev) => ({
        ...prev,
        status: endpoint === "approveItem" ? "approved" : "rejected",
      }));
    } catch (err) {
      console.error(err);
      setActionStatus("Action failed");
    } finally {
      setActionLoading(false);
      setTimeout(() => setActionStatus(""), 2000);
    }
  };

  // ================= LOADING / ERROR UI =================
  if (loading)
    return (
      <div className="flex items-center justify-center min-h-screen text-gray-500 animate-pulse">
        Loading item details...
      </div>
    );

  if (!item)
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <p className="text-xl font-semibold text-gray-600">Item not found</p>
        <button
          onClick={() => router.back()}
          className="mt-4 text-blue-600 hover:underline"
        >
          Go back
        </button>
      </div>
    );

  const photos = item.photos || [];

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header */}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <button
            onClick={() => router.back()}
            className="flex items-center text-gray-600 hover:text-gray-900 transition"
          >
            <ArrowLeft size={20} className="mr-2" /> Back to Items
          </button>
          <div className="flex gap-3">
            <span
              className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                item.status === "pending"
                  ? "bg-yellow-100 text-yellow-700"
                  : item.status === "approved"
                    ? "bg-green-100 text-green-700"
                    : "bg-red-100 text-red-700"
              }`}
            >
              {item.status.toUpperCase()}
            </span>
          </div>
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-6 mt-4">
        <h1 className="text-2xl font-bold text-gray-800 mb-8">Item Details</h1>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left Column: Item Info */}
          <div className="lg:col-span-2 space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div className="p-6">
                <div className="flex items-center mb-4 text-blue-600">
                  <Package size={22} className="mr-2" />
                  <h2 className="text-lg font-bold">Item Information</h2>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Item Photos */}
                  {photos.length > 0 && (
                    <div className="space-y-3">
                      <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">
                        Item Photos
                      </p>
                      <div className="grid grid-cols-2 gap-2">
                        {photos.map((img, i) => {
                          const src = img.startsWith("http")
                            ? img
                            : `${BASE_URL}${img.startsWith("/") ? "" : "/"}${img}`;
                          return (
                            <img
                              key={i}
                              src={src}
                              alt={item.itemName}
                              className="aspect-square w-full object-cover rounded-lg border bg-gray-50"
                            />
                          );
                        })}
                      </div>
                    </div>
                  )}

                  {/* Item Attributes */}
                  <div className="space-y-4">
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Name
                      </label>
                      <p className="text-gray-800 font-medium text-lg">
                        {item.itemName}
                      </p>
                    </div>
                    <div className="flex gap-10">
                      <div>
                        <label className="text-xs text-gray-400 font-bold uppercase">
                          Category
                        </label>
                        <p className="text-gray-700">{item.category}</p>
                      </div>
                      <div>
                        <label className="text-xs text-gray-400 font-bold uppercase">
                          Verified
                        </label>
                        <p
                          className={
                            item.isVerified
                              ? "text-green-600 font-bold"
                              : "text-gray-500"
                          }
                        >
                          {item.isVerified ? "✓ Yes" : "No"}
                        </p>
                      </div>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Location
                      </label>
                      <p className="text-gray-700">{item.location}</p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Type
                      </label>
                      <p className="text-gray-700">{item.type}</p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Description
                      </label>
                      <p className="text-gray-600 text-sm leading-relaxed">
                        {item.description}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>

          {/* Right Column: PostedBy + Actions */}
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <div className="flex items-center mb-6 text-gray-800">
                <User size={22} className="mr-2 text-green-600" />
                <h2 className="text-lg font-bold">Posted By</h2>
              </div>
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-green-100 text-green-700 flex items-center justify-center font-bold">
                    {item.postedBy?.name?.charAt(0)}
                  </div>
                  <div>
                    <p className="font-bold text-gray-800">
                      {item.postedBy?.name}
                    </p>
                    <p className="text-xs text-gray-500">
                      {item.postedBy?.email}
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Action Card */}
            <div className="bg-gray-100 rounded-2xl p-6 text-white shadow-xl">
              <h3 className="text-sm font-bold uppercase tracking-widest text-gray-400 mb-4">
                Actions
              </h3>
              {actionStatus && (
                <p className="text-center text-sm font-semibold text-gray-700 mb-3">
                  {actionStatus}
                </p>
              )}
              <div className="grid gap-3">
                <button
                  disabled={actionLoading}
                  onClick={() => handleAction("approveItem", "Approving...")}
                  className="w-full flex items-center justify-center bg-green-500 hover:bg-green-600 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-green-900/20 disabled:opacity-50"
                >
                  <CheckCircle size={20} className="mr-2" /> Approve
                </button>
                <button
                  disabled={actionLoading}
                  onClick={() => handleAction("rejectItem", "Rejecting...")}
                  className="w-full flex items-center justify-center bg-red-500 border border-red-500 hover:bg-red-600 text-white font-bold py-3 rounded-xl transition-all disabled:opacity-50"
                >
                  <XCircle size={20} className="mr-2" /> Reject
                </button>
              </div>
              <p className="text-[10px] text-gray-500 mt-4 text-center">
                Action will be logged and poster will be notified via email.
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default ItemDetailsPage;
